import{_ as t,o as n,c as i,ag as o}from"./chunks/framework.DXGyWiRo.js";const f=JSON.parse('{"title":"Frontend Supply-Chain Contracts","description":"","frontmatter":{},"headers":[],"relativePath":"frontend-supply-chain-contracts.md","filePath":"frontend-supply-chain-contracts.md","lastUpdated":1775910991000}'),a={name:"frontend-supply-chain-contracts.md"};function l(c,e,r,d,p,s){return n(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="frontend-supply-chain-contracts" tabindex="-1">Frontend Supply-Chain Contracts <a class="header-anchor" href="#frontend-supply-chain-contracts" aria-label="Permalink to &quot;Frontend Supply-Chain Contracts&quot;">​</a></h1><p>This document captures the contract-style verification for frontend supply-chain hardening.</p><h2 id="contract-a-lockfile-enforcement" tabindex="-1">Contract A: Lockfile Enforcement <a class="header-anchor" href="#contract-a-lockfile-enforcement" aria-label="Permalink to &quot;Contract A: Lockfile Enforcement&quot;">​</a></h2><p>Given:</p><ol><li><code>frontend/package.json</code> changes</li><li><code>frontend/package-lock.json</code> is not updated to match</li></ol><p>Expected:</p><ol><li>frontend governance checks fail before merge</li></ol><p>Enforced by:</p><ol><li><code>npm ci</code></li><li><code>frontend/scripts/check-dependency-policy.mjs</code></li></ol><h2 id="contract-b-script-blocking" tabindex="-1">Contract B: Script Blocking <a class="header-anchor" href="#contract-b-script-blocking" aria-label="Permalink to &quot;Contract B: Script Blocking&quot;">​</a></h2><p>Given:</p><ol><li>a dependency defines lifecycle scripts</li></ol><p>Expected:</p><ol><li>frontend CI does not execute them during install</li><li>any required follow-up setup runs as an explicit trusted step</li></ol><p>Enforced by:</p><ol><li><code>npm ci --ignore-scripts</code> in frontend CI</li><li>explicit Playwright browser installation step after install</li></ol><h2 id="contract-c-dependency-review" tabindex="-1">Contract C: Dependency Review <a class="header-anchor" href="#contract-c-dependency-review" aria-label="Permalink to &quot;Contract C: Dependency Review&quot;">​</a></h2><p>Given:</p><ol><li>a pull request changes frontend dependencies</li></ol><p>Expected:</p><ol><li>dependency deltas are visible in PR checks</li><li>vulnerable dependency additions are blocked at configured severity</li><li>direct dependencies without approved metadata are blocked</li></ol><p>Enforced by:</p><ol><li>GitHub dependency review</li><li><code>frontend/scripts/check-dependency-policy.mjs</code></li><li><code>npm audit --audit-level=high</code></li></ol><h2 id="contract-d-override-path" tabindex="-1">Contract D: Override Path <a class="header-anchor" href="#contract-d-override-path" aria-label="Permalink to &quot;Contract D: Override Path&quot;">​</a></h2><p>Given:</p><ol><li>a vulnerable transitive dependency can be fixed by version forcing</li></ol><p>Expected:</p><ol><li>the safer version can be pinned centrally without unrelated code changes</li></ol><p>Enforced by:</p><ol><li><code>frontend/package.json</code> <code>overrides</code></li><li>override metadata in <code>frontend/dependency-policy.json</code></li></ol><h2 id="contract-e-patch-path" tabindex="-1">Contract E: Patch Path <a class="header-anchor" href="#contract-e-patch-path" aria-label="Permalink to &quot;Contract E: Patch Path&quot;">​</a></h2><p>Given:</p><ol><li>a vulnerable or broken transitive dependency cannot be fixed by override alone</li></ol><p>Expected:</p><ol><li>a repo-managed patch can be applied centrally after install</li></ol><p>Enforced by:</p><ol><li><code>frontend/dependency-patches.json</code></li><li><code>frontend/patches/</code></li><li><code>frontend/scripts/apply-dependency-patches.mjs</code></li></ol><h2 id="contract-f-build-integrity" tabindex="-1">Contract F: Build Integrity <a class="header-anchor" href="#contract-f-build-integrity" aria-label="Permalink to &quot;Contract F: Build Integrity&quot;">​</a></h2><p>Given:</p><ol><li>frontend dependencies are installed via the hardened CI flow</li></ol><p>Expected:</p><ol><li>unit tests still pass</li><li>the frontend still builds</li></ol><p>Enforced by:</p><ol><li>frontend CI unit-test step</li><li>frontend CI build step</li><li>frontend Docker build path using <code>npm ci --ignore-scripts</code></li></ol><h2 id="contract-g-http-boundary-integrity" tabindex="-1">Contract G: HTTP Boundary Integrity <a class="header-anchor" href="#contract-g-http-boundary-integrity" aria-label="Permalink to &quot;Contract G: HTTP Boundary Integrity&quot;">​</a></h2><p>Given:</p><ol><li>theme preference HTTP flows are moved behind the internal client boundary</li></ol><p>Expected:</p><ol><li>auth headers remain centralized</li><li>JSON handling remains centralized</li><li>401/error handling stays consistent with the rest of the app</li></ol><p>Enforced by:</p><ol><li>using the internal API client for theme preference requests</li><li>existing HTTP client contract coverage in <code>frontend/src/api/http/__tests__/</code></li></ol>',51)])])}const u=t(a,[["render",l]]);export{f as __pageData,u as default};
